      e.stopPropagation();
      onAddToMover(symbol);
  };

  const handleNavigate = (e: React.MouseEvent, symbol: string) => {
      e.stopPropagation();
      if (onNavigateStock) {
          onNavigateStock(symbol, symbol);
          setIsOpen(false);
      }
  };

