        setIsTrackedStock(false);
    } else {
        addTrackedItem({ id: symbol, name: stockName, symbol, type: 'STOCK' });
        setIsTrackedStock(true);
        // If adding to track, remove from ignore if present
        if(isIgnoredStock) {
            removeIgnoredItem(symbol);
            setIsIgnoredStock(false);
        }
    }
  };

  const toggleIgnore = (e: React.MouseEvent) => {
      e.stopPropagation();
      if (isIgnoredStock) {
          removeIgnoredItem(symbol);
          setIsIgnoredStock(false);
      } else {
          addIgnoredItem(symbol);
          setIsIgnoredStock(true);
          // If ignoring, usually implies not tracking (or hiding it)
          if (isTrackedStock) {
             removeTrackedItem(symbol, 'STOCK');
             setIsTrackedStock(false);
          }
      }
  };

  const stockResults = results[symbol] || [];
  const isLoading = status === 'initializing' || status === 'polling';

  const renderSpecificCard = (indicator: string, data: any) => {
      switch(indicator) {
          case 'PE': return <PECard data={data} />;
          case 'DetailledPE': return <DetailedPECard data={data} />;
          case 'MFHoldings': return <MFHoldingsCard data={data} />;
          case 'QuaterlyHoldings': return <QuarterlyHoldingsCard data={data} />;
          case 'Bulk/Block Deals': return <BulkBlockDealsCard data={data} />;
          case 'Insider/SAST Deals': return <InsiderDealsCard data={data} />;
          case 'Technical': return <TechnicalCard data={data} />;
          case 'FinancialInsights': return <FinancialsCard data={data} />;
          default: return <DefaultInsightCard data={data} />;
      }
  };

  return (
    <div className="space-y-4 animate-fade-in">
       {/* Header */}
       <div 
          className="bg-white rounded-xl shadow-sm border border-gray-200 p-4 flex flex-col sm:flex-row items-center justify-between gap-4 cursor-pointer hover:bg-gray-50 transition-colors"
          onClick={() => setIsExpanded(!isExpanded)}
       >
           <div className="flex items-center gap-3">
               <div className="p-2 bg-indigo-50 rounded-lg text-indigo-600">
                   <Sparkles size={20} />
               </div>
               <div>
                   <h3 className="font-bold text-gray-900 flex items-center gap-2">
                       Deep Dive Analysis
                       {!isExpanded && <span className="text-xs text-gray-400 font-normal ml-2">({stockResults.length} indicators loaded)</span>}
                   </h3>
                   <p className="text-xs text-gray-500">Comprehensive indicators for {stockName}</p>
               </div>
           </div>

           <div className="flex items-center gap-3 w-full sm:w-auto">
               {isExpanded && (
                   <>
                       <button
                           onClick={toggleIgnore}
                           className={`flex-1 sm:flex-none flex items-center justify-center gap-2 px-4 py-2 rounded-lg text-sm font-medium transition-colors border ${
                               isIgnoredStock 
                               ? 'bg-red-50 text-red-700 border-red-200 hover:bg-red-100' 
                               : 'bg-white text-gray-500 border-gray-200 hover:bg-gray-50 hover:text-red-600'
                           }`}
                           title={isIgnoredStock ? "Remove from Ignore List" : "Ignore Stock (Hide from Intelligent Tracking)"}
                       >
                           <EyeOff size={16} />
                           <span className="hidden sm:inline">{isIgnoredStock ? 'Ignored' : 'Ignore'}</span>
                       </button>

                       <button
                           onClick={toggleTracking}
                           className={`flex-1 sm:flex-none flex items-center justify-center gap-2 px-4 py-2 rounded-lg text-sm font-medium transition-colors border ${
                               isTrackedStock 
                               ? 'bg-green-50 text-green-700 border-green-200 hover:bg-green-100' 
                               : 'bg-white text-gray-700 border-gray-200 hover:bg-gray-50'
                           }`}
                           title={isTrackedStock ? "Remove from Watchlist" : "Add to Watchlist"}
                       >
                           {isTrackedStock ? <Check size={16} /> : <Plus size={16} />}
                           <span className="hidden sm:inline">{isTrackedStock ? 'Tracked' : 'Track'}</span>
                       </button>

                       {stockResults.length > 0 && (
                           <button 
                               onClick={(e) => { e.stopPropagation(); setChatContext(stockResults.map(i => ({ symbol, indicator: i.indicatorName, data: i.data }))); }}
                               className="flex-1 sm:flex-none flex items-center justify-center gap-2 px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 text-sm font-medium transition-colors"
                           >
                               <MessageSquare size={16} />
                               Ask AI
                           </button>
                       )}

                       <button 
                           onClick={(e) => { e.stopPropagation(); startExtraction([symbol],1,true); }} //Changed intentionally to do force refresh
                           disabled={isLoading}
                           className={`flex-1 sm:flex-none flex items-center justify-center gap-2 px-4 py-2 border border-gray-200 text-gray-700 rounded-lg hover:bg-gray-50 text-sm font-medium transition-colors ${isLoading ? 'opacity-75 cursor-not-allowed' : ''}`}
                           title='Force refresh'
                       >
                           {isLoading ? (
                               <>
                                 <Loader2 size={16} className="animate-spin" />
                                 <span className="hidden sm:inline">{progress.total > 0 ? `${progress.completed}/${progress.total}` : 'Loading...'}</span>
                               </>
                           ) : (
                               <>
                                 <RefreshCw size={16} />

                               </>
                           )}
                       </button>
                   </>
               )}

               <div className="p-2 text-gray-400">
                   {isExpanded ? <ChevronUp size={20} /> : <ChevronDown size={20} />}
               </div>
           </div>
       </div>

       {/* Grid Content */}
       {isExpanded && (
           <>
               {stockResults.length > 0 ? (
                   <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                       {stockResults.map((item, idx) => (
                           <BaseInsightCard
                                key={`${item.indicatorName}-${idx}`}
                                symbol={symbol}
                                indicatorName={item.indicatorName}
                                url={item.url}
                                isProcessing={false} // Hook handles data readiness
                                success={item.success}
                                isSelected={false}
                                onToggleSelect={() => {}} // No selection in this view
                                // onStockClick is undefined, so it renders as text
                           >
                               {renderSpecificCard(item.indicatorName, item.data)}
                           </BaseInsightCard>
                       ))}
                   </div>
               ) : (
                   isLoading ? (
                       <div className="grid grid-cols-1 md:grid-cols-3 gap-4 animate-pulse">
                           {[...Array(3)].map((_, i) => (
                               <div key={i} className="h-48 bg-white rounded-xl border border-gray-100 p-4">
                                   <div className="h-4 bg-gray-100 rounded w-1/3 mb-4"></div>
                                   <div className="space-y-2">
                                       <div className="h-3 bg-gray-100 rounded w-full"></div>
                                       <div className="h-3 bg-gray-100 rounded w-5/6"></div>
                                   </div>
                               </div>
                           ))}
                       </div>
                   ) : (
                       <div className="text-center py-12 bg-white rounded-xl border border-dashed border-gray-300">
                           <p className="text-gray-500">Click "Refresh Analysis" to load detailed indicators.</p>
                       </div>
                   )
               )}
           </>
       )}

       {/* Chatbot Overlay */}
       {chatContext && (
           <InsightChatbot contextData={chatContext} onClose={() => setChatContext(null)} />
       )}
    </div>
  );
};

export default StockDeepDive;

import React, { useEffect, useState, useMemo } from 'react';
import { ArrowLeft, ExternalLink,History, TrendingUp, TrendingDown, Layers, Loader2, Search, Filter, ArrowUp, ArrowDown, ChevronLeft, ChevronRight, BarChart2, RefreshCw, ChevronDown, ChevronUp, CheckSquare, Square } from 'lucide-react';
import { StockPriceData, StockMFAnalysis, MutualFundHolding, FundSearchResult } from '../types';
import { fetchLiveStockPrice, fetchMutualFundHoldingsForStock } from '../services/dataService';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';
import StockDeepDive from './StockDeepDive';
import { getTrackedItems, addTrackedItem, removeTrackedItem } from '../services/trackingStorage';

interface StockDashboardProps {
  symbol: string;
  stockName: string;
  onBack: () => void;
  onSelectFund: (fund: FundSearchResult) => void;
}

type SortField = 'sharesHeld' | 'aum' | 'changePercent' | 'change' | 'aumPercent';
type SortDirection = 'asc' | 'desc';

const ITEMS_PER_PAGE = 50;

const StockDashboard: React.FC<StockDashboardProps> = ({ symbol, stockName, onBack, onSelectFund }) => {
  const [priceData, setPriceData] = useState<StockPriceData | null>(null);
  const [loadingPrice, setLoadingPrice] = useState(false);

  const [mfData, setMfData] = useState<StockMFAnalysis | null>(null);
  const [loadingMF, setLoadingMF] = useState(false);

  const [filterQuery, setFilterQuery] = useState('');

  // Sorting State
  const [sortField, setSortField] = useState<SortField>('sharesHeld');
  const [sortMonth, setSortMonth] = useState<string | null>(null);
  const [sortDirection, setSortDirection] = useState<SortDirection>('desc');

  // Pagination State
  const [currentPage, setCurrentPage] = useState(1);

  // Section visibility states
  const [isHoldingsExpanded, setIsHoldingsExpanded] = useState(true);

  // MF Tracking State
  const [trackedMFSet, setTrackedMFSet] = useState<Set<string>>(new Set());
  const [showTrackedOnly, setShowTrackedOnly] = useState(false);

  // Load tracked items
  useEffect(() => {
      const updateTracked = () => {
          const items = getTrackedItems().filter(i => i.type === 'MF');
          setTrackedMFSet(new Set(items.map(i => i.id))); // Use ID which might be PK or Name
      };
      updateTracked();
      window.addEventListener('fundflow_tracking_update', updateTracked);
      return () => window.removeEventListener('fundflow_tracking_update', updateTracked);
  }, []);

  const loadData = async () => {
      setLoadingPrice(true);
      setLoadingMF(true);

      const p1 = fetchLiveStockPrice(symbol).then(data => {
        setPriceData(data);
        setLoadingPrice(false);
      });

      const p2 = fetchMutualFundHoldingsForStock(symbol).then(data => {
        setMfData(data);
        setLoadingMF(false);
      });

      await Promise.all([p1, p2]);
  };

  // Fetch Data on Mount
  useEffect(() => {
    loadData();
  }, [symbol, stockName]);

  const handleRefreshPrice = async () => {
    setLoadingPrice(true);
    const data = await fetchLiveStockPrice(symbol);
    setPriceData(data);
    setLoadingPrice(false);
  };

  const handleRefreshAll = () => {
      loadData();
  };

  // Determine available months from data
  const monthColumns = useMemo(() => {
    if (!mfData || mfData.holdings.length === 0) return [];
    const allMonths = Array.from(new Set(mfData.holdings.flatMap(h => h.history.map(hist => hist.month)))) as string[];
    // Sort descending by date
    const sortedMonths = allMonths.sort((a, b) => new Date(b).getTime() - new Date(a).getTime()).slice(0, 3);

    // Set default sort month if not set
    if (!sortMonth && sortedMonths.length > 0) {
      setSortMonth(sortedMonths[0]);
    }

    return sortedMonths;
  }, [mfData, sortMonth]);

  // Helper to extract ID from URL or Name
  const getMfId = (url: string, name: string) => {
      const matches = url.match(/\/(\d+)\//);
      if (matches && matches[1]) return matches[1];
      return name;
  };

  const handleTrackMF = (e: React.MouseEvent, mfName: string, mfUrl: string) => {
      e.stopPropagation();
      const id = getMfId(mfUrl, mfName);

      // Check if tracked by checking if ID is in set or Name is in set (fallback)
      const isTracked = trackedMFSet.has(id) || trackedMFSet.has(mfName);

      if (isTracked) {
          // Try removing by both potential keys
          removeTrackedItem(id, 'MF');
          removeTrackedItem(mfName, 'MF');
      } else {
          addTrackedItem({ id, name: mfName, type: 'MF', url: mfUrl });
      }
  };

  // Filter and Sort Logic
  const filteredSortedHoldings = useMemo(() => {
    if (!mfData) return [];

    let result = mfData.holdings.filter(h => 
      h.fundName.toLowerCase().includes(filterQuery.toLowerCase())
    );

    if (showTrackedOnly) {
        result = result.filter(h => {
            const id = getMfId(h.fundUrl, h.fundName);
            return trackedMFSet.has(id) || trackedMFSet.has(h.fundName);
        });
    }

    const targetMonth = sortMonth || monthColumns[0];

    result.sort((a, b) => {
      const dataA = a.history.find(h => h.month === targetMonth);
      const dataB = b.history.find(h => h.month === targetMonth);

      // Handle missing data for specific months (treat as 0 or min value)
      const valA = dataA ? (dataA[sortField] || 0) : -Infinity;
      const valB = dataB ? (dataB[sortField] || 0) : -Infinity;

      if (valA < valB) return sortDirection === 'asc' ? -1 : 1;
      if (valA > valB) return sortDirection === 'asc' ? 1 : -1;
      return 0;
    });

    return result;
  }, [mfData, filterQuery, sortField, sortDirection, sortMonth, monthColumns, showTrackedOnly, trackedMFSet]);

  // Pagination Logic
  const totalPages = Math.ceil(filteredSortedHoldings.length / ITEMS_PER_PAGE);
  const paginatedHoldings = useMemo(() => {
    const startIndex = (currentPage - 1) * ITEMS_PER_PAGE;
    return filteredSortedHoldings.slice(startIndex, startIndex + ITEMS_PER_PAGE);
  }, [filteredSortedHoldings, currentPage]);

  // Reset pagination when filter/sort changes
  useEffect(() => {
    setCurrentPage(1);
  }, [filterQuery, sortField, sortDirection, sortMonth, showTrackedOnly]);

  const handleSort = (field: SortField, month: string) => {
    if (sortField === field && sortMonth === month) {
      setSortDirection(sortDirection === 'asc' ? 'desc' : 'asc');
    } else {
      setSortField(field);
      setSortMonth(month);
      setSortDirection('desc');
    }
  };

  const SortIcon = ({ field, month }: { field: SortField, month: string }) => {
    const isActive = sortField === field && sortMonth === month;
    if (!isActive) return <div className="w-3 h-3 ml-1 opacity-0 group-hover:opacity-30"></div>;
    return sortDirection === 'asc' 
      ? <ArrowUp size={12} className="ml-1 text-indigo-600" />
      : <ArrowDown size={12} className="ml-1 text-indigo-600" />;
  };

  return (
    <div className="space-y-6 animate-fade-in pb-10">
      <div className="flex justify-between items-center">
        <button 
          onClick={onBack}
          className="flex items-center gap-2 text-sm text-gray-500 hover:text-indigo-600 transition-colors"
        >
          <ArrowLeft size={16} />
          Back to Search
        </button>
      </div>

      {/* Top Section: Price & Graph */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Price Card */}
        <div className="bg-white rounded-2xl p-6 shadow-sm border border-gray-100 flex flex-col justify-between">
          <div>
            <div className="flex justify-between items-start mb-4">
              <div>
                <h1 className="text-2xl font-bold text-gray-900 flex items-center gap-2">
                  {stockName}
                  {mfData?.sourceUrl && (
                    <a 
                      href={mfData.sourceUrl} 
                      target="_blank" 
                      rel="noreferrer"
                      className="text-gray-400 hover:text-indigo-600 transition-colors"
                      title="View full report on Trendlyne"
                    >
                      <ExternalLink size={20} />
                    </a>
                  )}
                  <button 
                    onClick={handleRefreshAll} 
                    disabled={loadingPrice || loadingMF}
                    className="p-1.5 rounded-full hover:bg-gray-100 text-gray-400 hover:text-indigo-600 transition-colors"
                    title="Refresh All Data"
                  >
                     <RefreshCw size={18} className={loadingPrice || loadingMF ? "animate-spin text-indigo-600" : ""} />
                  </button>
                </h1>
                <div className="flex items-center gap-2 text-gray-500 text-sm mt-1 flex-wrap">
                  <span className="font-mono bg-gray-100 px-2 py-0.5 rounded text-xs">{symbol}</span>
                  <span>•</span>
                  <span>NSE/BSE</span>
                  {mfData && (
                    <>
                      <span>•</span>
                      <span className="font-medium text-indigo-600 bg-indigo-50 px-2 py-0.5 rounded text-xs">
                         MF Count: {mfData.holdings.length}
                      </span>
                    </>
                  )}
                </div>
              </div>
              {priceData ? (
                <div className="text-right">
                    <div className="flex items-center justify-end gap-3 mb-1">
                        <div className="text-2xl font-bold text-gray-900">₹{priceData.current_price}</div>
                        <button 
                            onClick={handleRefreshPrice} 
                            disabled={loadingPrice}
                            className="p-1.5 rounded-full hover:bg-gray-100 text-gray-400 hover:text-indigo-600 transition-colors"
                            title="Refresh Price Only"
                        >
                            <RefreshCw size={14} className={loadingPrice ? "animate-spin" : ""} />
                        </button>
                    </div>

                    <div className="flex items-center justify-end gap-2 text-sm">
                        <span className="text-gray-500 font-medium text-xs bg-gray-50 px-1.5 py-0.5 rounded" title="Volume">
                           V: {priceData.volume}
                        </span>
                        <span className={`flex items-center font-medium ${
                           priceData.todays_change_direction === 'up' ? 'text-green-600' : 
                           priceData.todays_change_direction === 'down' ? 'text-red-600' : 'text-gray-500'
                        }`}>
                            {priceData.todays_change_direction === 'up' ? <TrendingUp size={14} className="mr-1" /> : 
                             priceData.todays_change_direction === 'down' ? <TrendingDown size={14} className="mr-1" /> : null}
                            {priceData.todays_change_number} ({priceData.todays_change_percentage})
                        </span>
                    </div>
                    <div className="text-[10px] text-gray-400 mt-1">
                       Updated: {priceData.last_updated}
                    </div>
                </div>
              ) : loadingPrice ? (
                 <div className="text-right">
                    <div className="h-8 w-24 bg-gray-100 animate-pulse rounded mb-1 ml-auto"></div>
                    <div className="h-4 w-16 bg-gray-100 animate-pulse rounded ml-auto"></div>
                 </div>
              ) : null}
            </div>

            {loadingPrice && !priceData && (
              <div className="flex items-center gap-2 text-indigo-600 text-sm mt-2">
                <Loader2 className="animate-spin" size={16} /> Fetching live price...
              </div>
            )}

          </div>

          <div className="mt-6 pt-6 border-t border-gray-100">
             <div className="text-sm text-gray-500 mb-1">Stock Analysis</div>
             <p className="text-xs text-gray-400">
               Real-time data fetched from market sources via Gemini. MF data aggregated from monthly disclosures.
             </p>
          </div>
        </div>
      </div>

      {/* Deep Dive Analysis Component (Collapsible Managed Internally) */}
      <StockDeepDive symbol={symbol} stockName={stockName} />

      {/* Holdings Table Section */}
      <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden flex flex-col">
        {/* Header */}
        <div 
            className="p-4 border-b border-gray-100 bg-gray-50 flex flex-col md:flex-row gap-4 items-center justify-between cursor-pointer hover:bg-gray-100 transition-colors"
            onClick={() => setIsHoldingsExpanded(!isHoldingsExpanded)}
        >
           <div className="flex items-center gap-3">
               <div className="p-1.5 bg-indigo-50 text-indigo-600 rounded-lg">
                   <Layers size={18} />
               </div>
               <h3 className="font-semibold text-gray-900 flex items-center gap-2">
                  Mutual Fund Portfolios
                  {!isHoldingsExpanded && <span className="text-xs text-gray-400 font-normal">({filteredSortedHoldings.length} records)</span>}
               </h3>
           </div>

           <div className="flex items-center gap-4 w-full md:w-auto" onClick={(e) => e.stopPropagation()}>
               {/* Tracked Filter */}
               {isHoldingsExpanded && (
                   <label className="flex items-center gap-1.5 text-xs text-gray-600 cursor-pointer select-none bg-white px-2 py-1.5 rounded-lg border border-gray-200 hover:border-indigo-200 transition-all">
                        <input 
                            type="checkbox" 
                            checked={showTrackedOnly} 
                            onChange={(e) => setShowTrackedOnly(e.target.checked)}
                            className="w-3.5 h-3.5 rounded border-gray-300 text-indigo-600 focus:ring-indigo-500 cursor-pointer"
                        />
                        <span className="font-medium">Tracked MFs</span>
                        {showTrackedOnly && (
                            <span className="bg-indigo-100 text-indigo-700 text-[10px] px-1.5 rounded-full font-bold">
                                {filteredSortedHoldings.length}
                            </span>
                        )}
                   </label>
               )}

               {/* Search */}
               {isHoldingsExpanded && (
                   <div className="relative w-full md:w-64">
                      <div className="absolute inset-y-0 left-0 flex items-center pl-3 pointer-events-none">
                        <Search className="w-4 h-4 text-gray-400" />
                      </div>
                      <input 
                        type="text" 
                        className="bg-white border border-gray-200 text-gray-900 text-sm rounded-lg focus:ring-indigo-500 focus:border-indigo-500 block w-full pl-9 p-2 shadow-sm" 
                        placeholder="Filter funds..." 
                        value={filterQuery}
                        onChange={(e) => setFilterQuery(e.target.value)}
                      />
                   </div>
               )}

               <button 
                   className="text-gray-400 hover:text-gray-600"
                   onClick={() => setIsHoldingsExpanded(!isHoldingsExpanded)}
               >
                   {isHoldingsExpanded ? <ChevronUp size={20} /> : <ChevronDown size={20} />}
               </button>
           </div>
        </div>

        {/* Collapsible Content */}
        {isHoldingsExpanded && (
            <>
                <div className="overflow-x-auto">
                  {loadingMF ? (
                    <div className="p-12 flex flex-col items-center justify-center text-gray-400 gap-3">
                       <Loader2 className="animate-spin text-indigo-500" size={32} />
                       <p>Fetching detailed holdings...</p>
                    </div>
                  ) : (
                    <table className="w-full text-sm text-left text-gray-500 border-collapse">
                      <thead className="text-xs text-gray-700 uppercase bg-gray-50 border-b border-gray-200">
                        {/* Header Row 1: Grouped Month Names */}
                        <tr>
                          <th rowSpan={2} className="px-6 py-4 font-semibold border-r border-gray-200 bg-gray-50 sticky left-0 z-10 w-64 min-w-[250px]">
                            MF Name
                          </th>
                          {monthColumns.map((month, index) => (
                            <th 
                              key={month} 
                              colSpan={index === 0 ? 4 : 2} // Latest month gets 4 columns (removed AUM Cr), others get 2
                              className={`px-4 py-2 text-center border-r border-gray-200 ${index === 0 ? 'bg-indigo-50 text-indigo-900 font-bold' : ''}`}
                            >
                              {month}
                            </th>
                          ))}
                        </tr>
                        {/* Header Row 2: Columns */}
                        <tr>
                          {monthColumns.map((month, index) => (
                             <React.Fragment key={`${month}-subheaders`}>
                               {index === 0 ? (
                                 // Full columns for latest month (Removed AUM Cr)
                                 <>
                                   <th 
                                     className="px-4 py-2 text-right cursor-pointer hover:bg-gray-100 group border-r border-gray-100"
                                     onClick={() => handleSort('aumPercent', month)}
                                   >
                                     <div className="flex items-center justify-end">AUM % <SortIcon field="aumPercent" month={month}/></div>
                                   </th>
                                   <th 
                                     className="px-4 py-2 text-right cursor-pointer hover:bg-gray-100 group border-r border-gray-100"
                                     onClick={() => handleSort('sharesHeld', month)}
                                   >
                                     <div className="flex items-center justify-end">Shares Held <SortIcon field="sharesHeld" month={month}/></div>
                                   </th>
                                   <th 
                                     className="px-4 py-2 text-right cursor-pointer hover:bg-gray-100 group border-r border-gray-100"
                                     onClick={() => handleSort('change', month)}
                                   >
                                     <div className="flex items-center justify-end">Month Change <SortIcon field="change" month={month}/></div>
                                   </th>
                                   <th 
                                     className="px-4 py-2 text-right cursor-pointer hover:bg-gray-100 group border-r border-gray-200"
                                     onClick={() => handleSort('changePercent', month)}
                                   >
                                     <div className="flex items-center justify-end">Change % <SortIcon field="changePercent" month={month}/></div>
                                   </th>
                                 </>
                               ) : (
                                 // Reduced columns for other months
                                 <>
                                   <th 
                                    className="px-4 py-2 text-right cursor-pointer hover:bg-gray-100 group border-r border-gray-100"
                                    onClick={() => handleSort('sharesHeld', month)}
                                   >
                                     <div className="flex items-center justify-end">Shares Held <SortIcon field="sharesHeld" month={month}/></div>
                                   </th>
                                   <th 
                                    className="px-4 py-2 text-right cursor-pointer hover:bg-gray-100 group border-r border-gray-200"
                                    onClick={() => handleSort('changePercent', month)}
                                   >
                                     <div className="flex items-center justify-end">Change % <SortIcon field="changePercent" month={month}/></div>
                                   </th>
                                 </>
                               )}
                             </React.Fragment>
                          ))}
                        </tr>
                      </thead>
                      <tbody className="divide-y divide-gray-100">
                        {paginatedHoldings.length > 0 ? paginatedHoldings.map((holding, idx) => {
                            const mfId = getMfId(holding.fundUrl, holding.fundName);
                            const isTracked = trackedMFSet.has(mfId) || trackedMFSet.has(holding.fundName);

                            return (
                              <tr key={idx} className="bg-white hover:bg-gray-50 transition-colors">
                                <td className="px-6 py-4 border-r border-gray-100 sticky left-0 bg-white group-hover:bg-gray-50 z-10">
                                  <div className="flex items-center gap-3">
                                    {/* Track Toggle */}
                                    <button 
                                        onClick={(e) => handleTrackMF(e, holding.fundName, holding.fundUrl)}
                                        className={`transition-colors ${isTracked ? 'text-indigo-600' : 'text-gray-300 hover:text-gray-500'}`}
                                        title={isTracked ? "Remove MF from Watchlist" : "Add MF to Watchlist"}
                                    >
                                        {isTracked ? <CheckSquare size={16} /> : <Square size={16} />}
                                    </button>

                                    <div className="flex items-center gap-2 group/link">
                                      {holding.historyUrl && (
                                         <a 
                                           href={holding.historyUrl} 
                                           target="_blank" 
                                           rel="noreferrer"
                                           className="text-gray-300 hover:text-indigo-500 transition-colors opacity-0 group-hover/link:opacity-100"
                                           title="View on Trendlyne"
                                         >
                                           <History size={14} />
                                         </a>
                                      )}
                                      <button 
                                        onClick={() => onSelectFund({ name: holding.fundName, url: holding.fundUrl })}
                                        className="font-medium text-indigo-600 hover:text-indigo-800 text-left transition-colors line-clamp-2"
                                      >
                                        {holding.fundName}
                                      </button>
                                      {holding.fundUrl && (
                                         <a 
                                           href={holding.fundUrl} 
                                           target="_blank" 
                                           rel="noreferrer"
                                           className="text-gray-300 hover:text-indigo-500 transition-colors opacity-0 group-hover/link:opacity-100"
                                           title="View on Trendlyne"
                                         >
                                           <ExternalLink size={14} />
                                         </a>
                                      )}
                                    </div>
                                  </div>
                                </td>

                                {monthColumns.map((month, mIndex) => {
                                  const data = holding.history.find(h => h.month === month);
                                  const isLatest = mIndex === 0;

                                  if (!data) {
                                    return (
                                      <React.Fragment key={`${month}-empty`}>
                                         {isLatest ? (
                                           <>
                                             <td className="px-4 py-4 text-right text-gray-300 border-r border-gray-100">-</td>
                                             <td className="px-4 py-4 text-right text-gray-300 border-r border-gray-100">-</td>
                                             <td className="px-4 py-4 text-right text-gray-300 border-r border-gray-100">-</td>
                                             <td className="px-4 py-4 text-right text-gray-300 border-r border-gray-200">-</td>
                                           </>
                                         ) : (
                                           <>
                                             <td className="px-4 py-4 text-right text-gray-300 border-r border-gray-100">-</td>
                                             <td className="px-4 py-4 text-right text-gray-300 border-r border-gray-200">-</td>
                                           </>
                                         )}
                                      </React.Fragment>
                                    );
                                  }

                                  return (
                                    <React.Fragment key={`${month}-data`}>
                                      {isLatest ? (
                                         <>
                                           {/* AUM % */}
                                           <td className="px-4 py-4 text-right font-mono text-gray-700 border-r border-gray-100 bg-indigo-50/20">
                                             {data.aumPercent ? `${data.aumPercent.toFixed(2)}%` : '-'}
                                           </td>
                                           {/* Shares Held */}
                                           <td className="px-4 py-4 text-right font-mono text-gray-900 font-medium border-r border-gray-100 bg-indigo-50/30">
                                             {data.sharesHeld.toLocaleString()}
                                           </td>
                                           {/* Month Change (Absolute) */}
                                           <td className="px-4 py-4 text-right font-mono border-r border-gray-100 bg-indigo-50/20">
                                              {data.change ? (
                                                 <span className={data.change > 0 ? 'text-green-600' : data.change < 0 ? 'text-red-600' : 'text-gray-400'}>
                                                   {data.change.toLocaleString()}
                                                 </span>
                                              ) : <span className="text-gray-300">0</span>}
                                           </td>
                                           {/* Month Change % */}
                                           <td className="px-4 py-4 text-right font-mono border-r border-gray-200 bg-indigo-50/20">
                                             <div className={`flex items-center justify-end gap-1 ${
                                               data.changePercent > 0 ? 'text-green-600 font-medium' : 
                                               data.changePercent < 0 ? 'text-red-600 font-medium' : 'text-gray-400'
                                             }`}>
                                                {data.changePercent > 0 ? `+${data.changePercent}%` : `${data.changePercent}%`}
                                             </div>
                                           </td>
                                         </>
                                      ) : (
                                         <>
                                           {/* Previous Month Shares */}
                                           <td className="px-4 py-4 text-right font-mono text-gray-600 border-r border-gray-100">
                                             {data.sharesHeld.toLocaleString()}
                                           </td>
                                           {/* Previous Month Change % */}
                                           <td className="px-4 py-4 text-right font-mono border-r border-gray-200">
                                             <span className={data.changePercent > 0 ? 'text-green-600' : data.changePercent < 0 ? 'text-red-600' : 'text-gray-400'}>
                                               {data.changePercent}%
                                             </span>
                                           </td>
                                         </>
                                      )}
                                    </React.Fragment>
                                  );
                                })}
                              </tr>
                            );
                        }) : (
                           <tr>
                             <td colSpan={1 + (monthColumns.length * 2) + 2} className="px-6 py-12 text-center text-gray-400">
                               {showTrackedOnly ? "No tracked funds in this stock's holdings." : "No funds found matching your search."}
                             </td>
                           </tr>
                        )}
                      </tbody>
                    </table>
                  )}
                </div>

                {mfData && filteredSortedHoldings.length > 0 && (
                  <div className="p-4 bg-gray-50 border-t border-gray-200 flex flex-col sm:flex-row items-center justify-between gap-4">
                    <div className="text-xs text-gray-500">
                      Showing {paginatedHoldings.length} of {filteredSortedHoldings.length} funds
                      {mfData.sourceUrl && " • Data Source: Trendlyne"}
                    </div>

                    <div className="flex items-center gap-2">
                      <button
                        onClick={() => setCurrentPage(prev => Math.max(prev - 1, 1))}
                        disabled={currentPage === 1}
                        className="p-2 rounded-lg border border-gray-200 bg-white text-gray-600 disabled:opacity-50 disabled:cursor-not-allowed hover:bg-gray-100 transition-colors"
                      >
                        <ChevronLeft size={16} />
                      </button>

                      <span className="text-sm font-medium text-gray-700 px-2">
                        Page {currentPage} of {totalPages}
                      </span>

                      <button
                        onClick={() => setCurrentPage(prev => Math.min(prev + 1, totalPages))}
                        disabled={currentPage === totalPages}
                        className="p-2 rounded-lg border border-gray-200 bg-white text-gray-600 disabled:opacity-50 disabled:cursor-not-allowed hover:bg-gray-100 transition-colors"
                      >
                        <ChevronRight size={16} />
                      </button>
                    </div>
                  </div>
                )}
            </>
        )}
      </div>
    </div>
  );
};

export default StockDashboard;

import React, { useState, useEffect, useMemo } from 'react';
import { Loader2, RefreshCw, Filter, BrainCircuit, ChevronDown, ChevronLeft, ChevronRight, Search, EyeOff, Plus } from 'lucide-react';
import { fetchIndexConstituents } from '../../services/dataService';
import { processIndicatorData, ProcessedInsight } from '../../services/indicatorProcessor';
import { isTracked, addTrackedItem, removeTrackedItem, getTrackedIndices, getIgnoredItems, addIgnoredItem } from '../../services/trackingStorage';
import IntelligentStockCard from './cards/IntelligentStockCard';
import { InsightResultItem, IntelligentState } from '../../types/trackingTypes';

interface IntelligentTrackingManagerProps {
  onOpenChat: (context: any[]) => void;
  onSelectStock: (symbol: string, name: string) => void;
  // Props from parent hook
  extractionData: {
      results: Record<string, InsightResultItem[]>;
      status: 'idle' | 'initializing' | 'polling' | 'completed' | 'error';
      startExtraction: (symbols: string[], batchSize?: number, invalidateCache?: boolean) => Promise<void>;
      progress: { completed: number; total: number };
  };
  onStatsUpdate: (stats: { filtered: number; total: number; ignoredList: string[] }) => void;
  // Persisted View State
  viewState: IntelligentState;
  setViewState: React.Dispatch<React.SetStateAction<IntelligentState>>;
}

const FILTER_TYPES: string[] = ["All", "Valuation", "Technicals", "Holdings", "Performance", "Deals"];
const BATCH_SIZE = 10;

const IntelligentTrackingManager: React.FC<IntelligentTrackingManagerProps> = ({ 
  onOpenChat, 
  onSelectStock,
  extractionData,
  onStatsUpdate,
  viewState,
  setViewState
}) => {
  const [loadingSymbols, setLoadingSymbols] = useState(false);
  const [trackTick, setTrackTick] = useState(0);
  const [availableIndices, setAvailableIndices] = useState<string[]>([]);
  const [searchQuery, setSearchQuery] = useState<string>('');

  // Selection and Force Refresh State
  const [selectedSymbols, setSelectedSymbols] = useState<Set<string>>(new Set());
  const [forceRefresh, setForceRefresh] = useState(false);

  // Ignore list state to filter locally
  const [ignoredItems, setIgnoredItems] = useState<string[]>([]);

  // Current Index Ignored List
  const [currentIndexIgnored, setCurrentIndexIgnored] = useState<string[]>([]);

  // Destructure hook data
  const { results, status, startExtraction, progress } = extractionData;

  // Local state for processed trigger data (Derived from results, so safe to be local)
  const [processedStocks, setProcessedStocks] = useState<Record<string, ProcessedInsight[]>>({});
  const [processingData, setProcessingData] = useState(false);

  // Helper to update specific view state fields
  const updateState = (updates: Partial<IntelligentState>) => {
      setViewState(prev => ({ ...prev, ...updates }));
  };

  // 0. Load Available Indices & Ignored List
  useEffect(() => {
    const loadData = () => {
        const indices = getTrackedIndices();
        setAvailableIndices(indices);
        setIgnoredItems(getIgnoredItems());

        // Safety check: if current selected index was deleted, default to first available
        if (indices.length > 0 && !indices.includes(viewState.selectedIndex)) {
            updateState({ selectedIndex: indices[0], symbols: [], page: 1 });
        }
    };
    loadData();

    // Listen for storage changes
    const handleUpdate = () => loadData();
    window.addEventListener('fundflow_tracking_update', handleUpdate);
    return () => window.removeEventListener('fundflow_tracking_update', handleUpdate);
  }, [viewState.selectedIndex]);

  // 1. Fetch Index Symbols on Change (Persisted in viewState.symbols)
  useEffect(() => {
     // If we already have symbols for this index, we still need to re-calculate ignored items 
     // because ignore list might have changed.

     // Only fetch if we have a valid selected index
     if (!viewState.selectedIndex) return;

     const loadSymbols = async () => {
         // Avoid re-fetching API if we just want to re-filter
         const alreadyLoaded = viewState.symbols.length > 0 && !loadingSymbols;

         if(!alreadyLoaded) setLoadingSymbols(true);

         try {
             // For simplicity, we always refetch constituents to ensure we get the full list for calculating ignored
             // Optimization: We could cache raw index response
             const allSymbols = await fetchIndexConstituents(viewState.selectedIndex);

             const ignored = getIgnoredItems();
             const ignoredInIndex = allSymbols.filter(s => ignored.includes(s));
             const cleanSymbols = allSymbols.filter(s => !ignored.includes(s));

             setCurrentIndexIgnored(ignoredInIndex);

             // Only update viewState if it actually changed (shallow check optimization implied)
             if (!alreadyLoaded || cleanSymbols.length !== viewState.symbols.length) {
                 updateState({ symbols: cleanSymbols, page: 1 }); 
                 setSelectedSymbols(new Set());
             }
         } catch (e) {
             console.error("Failed to fetch index symbols", e);
             updateState({ symbols: [] });
         } finally {
             setLoadingSymbols(false);
         }
     };
     loadSymbols();
  }, [viewState.selectedIndex, trackTick]); // re-run if tracking/ignore list changes (trackTick updates on ignore action)

  // 2. Start Extraction logic (Smart Refresh for Missing Symbols)
  useEffect(() => {
      const isFetching = status === 'initializing' || status === 'polling';
      if (viewState.symbols.length === 0 || isFetching) return;

      // Identify which symbols in the current view don't have results yet
      const missingSymbols = viewState.symbols.filter(sym => !results[sym] || results[sym].length === 0);

      if (missingSymbols.length > 0) {
          // Fetch only the missing ones (no force refresh for auto-fetch)
          startExtraction(missingSymbols, BATCH_SIZE, false);
      }
  }, [viewState.symbols, status, results, startExtraction]);

  // 3. Process Raw Results into Intelligent Insights
  useEffect(() => {
      const processResults = async () => {
          if (Object.keys(results).length === 0) {
              setProcessedStocks({});
              return;
          }

          setProcessingData(true);
          const newProcessed: Record<string, ProcessedInsight[]> = {};

          for (const [symbol, val] of Object.entries(results)) {
              const items = val as InsightResultItem[];
              // Optimization: Only process symbols relevant to current index to save performance
              if (!viewState.symbols.includes(symbol)) continue;

              const stockInsights: ProcessedInsight[] = [];
              for (const item of items) {
                  if (item.success && (item.type === 'json' || item.data)) {
                       // Fix: Cast item.data to any to avoid unknown type error
                       const insight = await processIndicatorData(symbol, item.indicatorName as string, item.data as any);
                       if (insight.status === 'triggered') {
                           stockInsights.push(insight);
                       }
                  }
              }
              if (stockInsights.length > 0) {
                  newProcessed[symbol] = stockInsights;
              }
          }
          setProcessedStocks(newProcessed);
          setProcessingData(false);
      };

      const timer = setTimeout(processResults, 1000);
      return () => clearTimeout(timer);
  }, [results, viewState.symbols]);

  // 4. Filter Logic
  const filteredStocks = useMemo(() => {
      return (Object.entries(processedStocks) as [string, ProcessedInsight[]][]).filter(([symbol, insights]) => {
          // 0. Double check ignore list
          if (ignoredItems.includes(symbol)) return false;

          // 1. Filter by Insight Type
          const matchesType = viewState.filter === "All" || insights.some(i => i.type === viewState.filter);
          if (!matchesType) return false;

          // 2. Filter by Search Query
          if (!searchQuery) return true;
          const lowerQ = searchQuery.toLowerCase();

          if (symbol.toLowerCase().includes(lowerQ)) return true;
          if (insights.some(i => i.text?.toLowerCase().includes(lowerQ))) return true;

          return false;
      }).sort((a, b) => b[1].length - a[1].length); 
  }, [processedStocks, viewState.filter, searchQuery, ignoredItems]);

  // 5. Pagination Logic
  const paginatedStocks = useMemo(() => {
      const startIndex = (viewState.page - 1) * viewState.pageSize;
      return filteredStocks.slice(startIndex, startIndex + viewState.pageSize);
  }, [filteredStocks, viewState.page, viewState.pageSize]);

  const totalPages = Math.ceil(filteredStocks.length / viewState.pageSize);

  // 6. Update Parent Stats
  useEffect(() => {
      onStatsUpdate({
          filtered: filteredStocks.length,
          total: viewState.symbols.length,
          ignoredList: currentIndexIgnored
      });
  }, [filteredStocks.length, viewState.symbols.length, currentIndexIgnored, onStatsUpdate]);

  const handleToggleSelect = (symbol: string) => {
      const newSet = new Set(selectedSymbols);
      if (newSet.has(symbol)) {
          newSet.delete(symbol);
      } else {
          newSet.add(symbol);
      }
      setSelectedSymbols(newSet);
  };

  const handleManualRefresh = () => {
      if (selectedSymbols.size > 0) {
          startExtraction(Array.from(selectedSymbols), BATCH_SIZE, true);
          setSelectedSymbols(new Set()); 
      } else if (viewState.symbols.length > 0) {
          startExtraction(viewState.symbols, BATCH_SIZE, forceRefresh);
      }
  };

  const handleIgnoreSelected = () => {
      if (selectedSymbols.size === 0) return;

      const toIgnore = Array.from(selectedSymbols);
      toIgnore.forEach(sym => addIgnoredItem(sym));

      setTrackTick(prev => prev + 1);
      setSelectedSymbols(new Set());
  };

  const handleTrackSelected = () => {
      if (selectedSymbols.size === 0) return;

      const toTrack = Array.from(selectedSymbols);
      toTrack.forEach(sym => {
          // Use symbol as name if full name isn't readily available in this context
          addTrackedItem({ id: sym, name: sym, symbol: sym, type: 'STOCK' });
      });

      setTrackTick(prev => prev + 1);
      setSelectedSymbols(new Set());
  };

  const handleCardRefresh = (symbol: string) => {
      startExtraction([symbol], 1, true);
  };

  return (
    <div className="space-y-6">
       {/* Controls Bar */}
       <div className="bg-white rounded-xl border border-gray-200 p-4 flex flex-col xl:flex-row items-center justify-between gap-4 shadow-sm">

           <div className="flex flex-col md:flex-row items-center gap-4 w-full xl:w-auto">
               {/* Index Selector */}
               <div className="relative w-full md:w-48">
                   <select 
                       value={viewState.selectedIndex}
                       onChange={(e: React.ChangeEvent<HTMLSelectElement>) => {
                           updateState({ selectedIndex: e.target.value, symbols: [], page: 1 }); 
                       }}
                       className="w-full appearance-none bg-gray-50 border border-gray-200 text-gray-700 text-sm font-medium rounded-lg pl-4 pr-10 py-2.5 focus:outline-none focus:ring-2 focus:ring-indigo-500 cursor-pointer"
                       disabled={loadingSymbols || status === 'initializing'}
                   >
                       {availableIndices.map((idx: string) => <option key={idx} value={idx}>{idx}</option>)}
                   </select>
                   <ChevronDown size={16} className="absolute right-3 top-1/2 transform -translate-y-1/2 text-gray-400 pointer-events-none" />
               </div>

                {/* Search Box */}
               <div className="relative w-full md:w-48">
                   <div className="absolute inset-y-0 left-0 flex items-center pl-3 pointer-events-none">
                        <Search size={16} className="text-gray-400" />
                   </div>
                   <input 
                       type="text"
                       value={searchQuery}
                       onChange={(e) => setSearchQuery(e.target.value)}
                       placeholder="Search insights..."
                       className="w-full bg-gray-50 border border-gray-200 text-gray-700 text-sm font-medium rounded-lg pl-9 pr-3 py-2.5 focus:outline-none focus:ring-2 focus:ring-indigo-500"
                   />
               </div>

               <div className="h-6 w-px bg-gray-200 hidden md:block"></div>

               {/* Filter Dropdown */}
               <div className="relative w-full md:w-48">
                   <div className="absolute inset-y-0 left-0 flex items-center pl-3 pointer-events-none">
                        <Filter size={16} className="text-gray-400" />
                   </div>
                   <select 
                       value={viewState.filter}
                       onChange={(e: React.ChangeEvent<HTMLSelectElement>) => updateState({ filter: e.target.value, page: 1 })}
                       className="w-full appearance-none bg-gray-50 border border-gray-200 text-gray-700 text-sm font-medium rounded-lg pl-9 pr-10 py-2.5 focus:outline-none focus:ring-2 focus:ring-indigo-500 cursor-pointer"
                   >
                       {FILTER_TYPES.map((type: string) => (
                           <option key={type} value={type}>{type} Insights</option>
                       ))}
                   </select>
                   <ChevronDown size={16} className="absolute right-3 top-1/2 transform -translate-y-1/2 text-gray-400 pointer-events-none" />
               </div>

                {/* Force Refresh Checkbox (Only visible if no selection, as selection implies force) */}
               {selectedSymbols.size === 0 && (
                   <label className="flex items-center gap-2 text-sm text-gray-600 cursor-pointer whitespace-nowrap ml-2">
                       <input 
                           type="checkbox" 
                           checked={forceRefresh} 
                           onChange={(e) => setForceRefresh(e.target.checked)}
                           className="w-4 h-4 text-indigo-600 border-gray-300 rounded focus:ring-indigo-500"
                       />
                       Invalidate Cache
                   </label>
               )}
           </div>

           {/* Right Side: Pagination & Status */}
           <div className="flex items-center gap-4 w-full xl:w-auto justify-between xl:justify-end">

               {filteredStocks.length > 0 && (
                   <div className="flex items-center gap-3">
                       <div className="flex items-center gap-2">
                           <span className="text-xs text-gray-500">Rows:</span>
                           <select 
                             value={viewState.pageSize} 
                             onChange={(e) => updateState({ pageSize: Number(e.target.value), page: 1 })}
                             className="bg-gray-50 border border-gray-200 text-gray-700 text-xs rounded-lg p-1.5"
                           >
                               <option value={10}>10</option>
                               <option value={20}>20</option>
                               <option value={50}>50</option>
                               <option value={100}>100</option>
                           </select>
                       </div>

                       <div className="flex items-center gap-1">
                            <button
                                onClick={() => updateState({ page: Math.max(1, viewState.page - 1) })}
                                disabled={viewState.page === 1}
                                className="p-1.5 rounded-md border border-gray-200 hover:bg-gray-50 disabled:opacity-50 disabled:cursor-not-allowed"
                            >
                                <ChevronLeft size={16} />
                            </button>
                            <span className="text-xs font-medium w-16 text-center">
                                {viewState.page} / {totalPages}
                            </span>
                            <button
                                onClick={() => updateState({ page: Math.min(totalPages, viewState.page + 1) })}
                                disabled={viewState.page === totalPages}
                                className="p-1.5 rounded-md border border-gray-200 hover:bg-gray-50 disabled:opacity-50 disabled:cursor-not-allowed"
                            >
                                <ChevronRight size={16} />
                            </button>
                       </div>
                   </div>
               )}

               <div className="h-6 w-px bg-gray-200 hidden xl:block"></div>

               {loadingSymbols ? (
                   <span className="text-xs text-gray-500 flex items-center gap-2">
                       <Loader2 size={14} className="animate-spin" /> Fetching Symbols...
                   </span>
               ) : status === 'initializing' || status === 'polling' ? (
                   <div className="flex items-center gap-3">
                       <span className="text-xs text-gray-500 flex items-center gap-2">
                           <Loader2 size={14} className="animate-spin text-indigo-600" /> 
                           Analyzing {progress.completed}/{progress.total}
                       </span>
                   </div>
               ) : selectedSymbols.size > 0 ? (
                   <div className="flex items-center gap-2">
                       <button 
                           onClick={handleTrackSelected}
                           className="flex items-center gap-2 px-3 py-2 bg-green-50 text-green-600 hover:bg-green-100 rounded-lg transition-colors text-sm font-medium whitespace-nowrap"
                           title="Add selected to Watchlist"
                       >
                           <Plus size={16} />
                           Track ({selectedSymbols.size})
                       </button>
                       <button 
                           onClick={handleIgnoreSelected}
                           className="flex items-center gap-2 px-3 py-2 bg-red-50 text-red-600 hover:bg-red-100 rounded-lg transition-colors text-sm font-medium whitespace-nowrap"
                           title="Add selected to Ignore List (Do not track)"
                       >
                           <EyeOff size={16} />
                           Ignore ({selectedSymbols.size})
                       </button>
                       <button 
                           onClick={handleManualRefresh}
                           className="flex items-center gap-2 px-3 py-2 bg-indigo-50 text-indigo-600 hover:bg-indigo-100 rounded-lg transition-colors text-sm font-medium whitespace-nowrap"
                           title="Force Refresh Selected"
                       >
                           <RefreshCw size={16} />
                           Refresh
                       </button>
                   </div>
               ) : (
                   <button 
                       onClick={handleManualRefresh}
                       className="p-2 text-gray-600 hover:text-indigo-600 hover:bg-gray-50 rounded-lg transition-colors border border-transparent hover:border-gray-200"
                       title="Refresh List"
                   >
                       <RefreshCw size={20} />
                   </button>
               )}
           </div>
       </div>

       {/* Content Grid */}
       {loadingSymbols ? (
           <div className="flex flex-col items-center justify-center py-20 text-gray-400">
               <Loader2 size={32} className="animate-spin text-indigo-500 mb-2" />
               <p className="text-sm">Loading Index Constituents...</p>
           </div>
       ) : paginatedStocks.length > 0 ? (
           <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
               {paginatedStocks.map(([symbol, insights]) => (
                   <IntelligentStockCard 
                       key={symbol}
                       symbol={symbol}
                       insights={insights}
                       isTracked={isTracked(symbol, 'STOCK')}
                       onOpenDeepDive={() => onSelectStock(symbol, symbol)}
                       onAskAI={() => onOpenChat(insights.map((i: ProcessedInsight) => ({ 
                           symbol, 
                           type: String(i.type || ''), 
                           insight: String(i.text || ''), 
                           rawData: i.data 
                       })))}
                       onRefresh={() => handleCardRefresh(symbol)}
                       isSelected={selectedSymbols.has(symbol)}
                       onToggleSelect={() => handleToggleSelect(symbol)}
                   />
               ))}
           </div>
       ) : (
           <div className="flex flex-col items-center justify-center py-20 bg-white rounded-xl border border-dashed border-gray-300">
               {status === 'initializing' || status === 'polling' || processingData ? (
                   <>
                      <BrainCircuit size={48} className="text-indigo-200 mb-4 animate-pulse" />
                      <h3 className="text-lg font-medium text-gray-900">Analysis in Progress</h3>
                      <p className="text-gray-500 mt-1">Processing data in batches of {BATCH_SIZE}...</p>
                   </>
               ) : (
                   <>
                      <p className="text-gray-500">No stocks found matching your criteria.</p>
                      <p className="text-xs text-gray-400 mt-1">Try changing the filter, search query, or refreshing analysis.</p>
                   </>
               )}
           </div>
       )}
    </div>
  );
};

export default IntelligentTrackingManager;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { Search, TrendingUp, TrendingDown, ArrowRight, ArrowLeft, ArrowUp, ArrowDown, Upload, Loader2, ExternalLink, History, ChevronLeft, ChevronRight, PieChart as PieIcon, Info, ChevronDown, ChevronUp, RefreshCw, CheckSquare, Square, Filter, Plus, Check } from 'lucide-react';
import { FundSnapshot, FundSearchResult, FundPortfolioHolding, FundMeta, SectorDistribution, HoldingHistoryItem } from '../types';
import { parseExcelFile, fetchFundPortfolio, fetchFundHoldingHistory } from '../services/dataService';
import { getTrackedItems, addTrackedItem, removeTrackedItem, isTracked } from '../services/trackingStorage';
import FundSearch from './FundSearch';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip, Legend } from 'recharts';

interface FundViewProps {
  funds: FundSnapshot[]; // For uploaded files
  onFundDataAdded: (data: FundSnapshot) => void;
  onSelectStock: (symbol: string, name: string) => void;
  initialSelectedFund?: FundSearchResult | null;
}

type SortField = 'stockName' | 'sector' | 'percentage' | 'quantity' | 'changePercentage' | string;
type SortDirection = 'asc' | 'desc';

const ITEMS_PER_PAGE = 50;
const CHART_COLORS = ['#6366f1', '#8b5cf6', '#ec4899', '#f43f5e', '#f97316', '#eab308', '#22c55e', '#06b6d4', '#3b82f6', '#64748b'];

const FundView: React.FC<FundViewProps> = ({ funds, onFundDataAdded, onSelectStock, initialSelectedFund }) => {
  const [selectedFund, setSelectedFund] = useState<FundSearchResult | null>(initialSelectedFund || null);

  // Data States
  const [portfolioData, setPortfolioData] = useState<FundPortfolioHolding[] | null>(null);
  const [fundMeta, setFundMeta] = useState<FundMeta | null>(null);
  const [sectorData, setSectorData] = useState<SectorDistribution[]>([]);

  const [loading, setLoading] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  // Tracking State
  const [showTrackedOnly, setShowTrackedOnly] = useState(false);
  const [trackedSet, setTrackedSet] = useState<Set<string>>(new Set());
  const [isFundTracked, setIsFundTracked] = useState(false);

  // History Data State
  const [historyCache, setHistoryCache] = useState<Record<string | number, { date: string, change: string }[]>>({});
  const [monthHeaders, setMonthHeaders] = useState<string[]>([]);
  const [loadingHistoryMap, setLoadingHistoryMap] = useState<Record<string | number, boolean>>({});

  // Sorting
  const [sortField, setSortField] = useState<SortField>('percentage');
  const [sortDirection, setSortDirection] = useState<SortDirection>('desc');

  // Pagination
  const [currentPage, setCurrentPage] = useState(1);

  // File Upload State
  const [isUploading, setIsUploading] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Sync prop changes
  useEffect(() => {
    if (initialSelectedFund) {
      setSelectedFund(initialSelectedFund);
    }
  }, [initialSelectedFund]);

  // Load tracked items
  useEffect(() => {
    const updateTracked = () => {
        const items = getTrackedItems().filter(i => i.type === 'STOCK');
        setTrackedSet(new Set(items.map(i => i.id)));
    };
    updateTracked();
    window.addEventListener('fundflow_tracking_update', updateTracked);
    return () => window.removeEventListener('fundflow_tracking_update', updateTracked);
  }, []);

  // Check if current fund is tracked
  useEffect(() => {
      const checkFundTracking = () => {
          if (!selectedFund) {
              setIsFundTracked(false);
              return;
          }
          const id = selectedFund.pk ? String(selectedFund.pk) : selectedFund.name;
          setIsFundTracked(isTracked(id, 'MF'));
      };
      checkFundTracking();
      window.addEventListener('fundflow_tracking_update', checkFundTracking);
      return () => window.removeEventListener('fundflow_tracking_update', checkFundTracking);
  }, [selectedFund]);

  const loadData = async () => {
      if (!selectedFund || !selectedFund.url) {
          setPortfolioData(null);
          setFundMeta(null);
          setSectorData([]);
          setHistoryCache({});
          setMonthHeaders([]);
          return;
      }

      setLoading(true);
      // Reset data to ensure clean state on refresh
      setPortfolioData(null); 
      setSectorData([]);

      try {
        const data = await fetchFundPortfolio(selectedFund.url);
        if (data) {
            setPortfolioData(data.holdings);
            setFundMeta(data.meta);
            setSectorData(data.sectorDistribution);
        } else {
            setPortfolioData([]);
            setFundMeta(null);
            setSectorData([]);
        }
      } catch (err) {
          console.error("Failed to load fund portfolio", err);
          setPortfolioData([]);
      } finally {
          setLoading(false);
      }
  };

  // Fetch API Data whenever selectedFund changes
  useEffect(() => {
    loadData();
  }, [selectedFund]);

  const handleRefresh = () => {
      loadData();
  };

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setIsUploading(true);
      try {
        const data = await parseExcelFile(e.target.files[0]);
        if (data) {
          onFundDataAdded(data);
          // Switch to offline view logic (not fully implemented in this iteration, keeping focus on API)
          setSelectedFund({ name: data.fundName, url: '' });
          alert("Offline file viewing is limited in this demo mode. Please use the API flow.");
        }
      } catch (err) {
        alert("Failed to upload file");
      } finally {
        setIsUploading(false);
      }
    }
  };

  const handleSort = (field: SortField) => {
    if (sortField === field) {
      setSortDirection(sortDirection === 'asc' ? 'desc' : 'asc');
    } else {
      setSortField(field);
      setSortDirection('desc');
    }
  };

  const handleTrackToggle = (e: React.MouseEvent, symbol: string, name: string) => {
      e.stopPropagation();
      if (trackedSet.has(symbol)) {
          removeTrackedItem(symbol, 'STOCK');
      } else {
          addTrackedItem({ id: symbol, name, symbol, type: 'STOCK' });
      }
  };

  const handleToggleFundTrack = (e: React.MouseEvent) => {
      e.stopPropagation();
      if (!selectedFund) return;

      const id = selectedFund.pk ? String(selectedFund.pk) : selectedFund.name;

      if (isFundTracked) {
          removeTrackedItem(id, 'MF');
      } else {
          addTrackedItem({
              id,
              name: selectedFund.name,
              type: 'MF',
              url: selectedFund.url
          });
      }
  };

  const sortedData = useMemo(() => {
      if (!portfolioData) return [];

      let data = [...portfolioData];

      // Filter by Search
      if (searchTerm) {
          const lower = searchTerm.toLowerCase();
          data = data.filter(item => 
              item.stockName.toLowerCase().includes(lower) || 
              item.stockSymbol.toLowerCase().includes(lower) ||
              item.sector.toLowerCase().includes(lower)
          );
      }

      // Filter by Tracked Only
      if (showTrackedOnly) {
          data = data.filter(item => trackedSet.has(item.stockSymbol));
      }

      return data.sort((a, b) => {
          let valA: any;
          let valB: any;

          // Check if sorting by history
          if (sortField.startsWith('history_')) {
              const index = parseInt(sortField.split('_')[1]);

              const getHistoryVal = (item: FundPortfolioHolding) => {
                  if (!item.stockPk) return -Infinity;
                  const history = historyCache[item.stockPk];
                  // If history not loaded or index out of bounds, treat as lowest value
                  if (!history || !history[index]) return -Infinity; 
                  return parseFloat(history[index].change.replace('%', '')) || 0;
              };

              valA = getHistoryVal(a);
              valB = getHistoryVal(b);
          } else {
              valA = a[sortField as keyof FundPortfolioHolding];
              valB = b[sortField as keyof FundPortfolioHolding];

              if (valA === undefined || valA === null) valA = sortField === 'stockName' || sortField === 'sector' ? '' : 0;
              if (valB === undefined || valB === null) valB = sortField === 'stockName' || sortField === 'sector' ? '' : 0;
          }

          // Handle strings
          if (typeof valA === 'string' && typeof valB === 'string') {
              valA = valA.toLowerCase();
              valB = valB.toLowerCase();
          }

          if (valA < valB) return sortDirection === 'asc' ? -1 : 1;
          if (valA > valB) return sortDirection === 'asc' ? 1 : -1;
          return 0;
      });
  }, [portfolioData, searchTerm, sortField, sortDirection, historyCache, showTrackedOnly, trackedSet]);

  // Pagination Logic
  const totalPages = Math.ceil(sortedData.length / ITEMS_PER_PAGE);
  const paginatedData = useMemo(() => {
    const startIndex = (currentPage - 1) * ITEMS_PER_PAGE;
    return sortedData.slice(startIndex, startIndex + ITEMS_PER_PAGE);
  }, [sortedData, currentPage]);

  // Reset pagination when filter/sort changes
  useEffect(() => {
    setCurrentPage(1);
    // Note: We don't clear historyCache here to preserve loaded data if user navigates back
  }, [searchTerm, sortField, sortDirection, selectedFund, showTrackedOnly]);

  // --- Fetch History for Visible Rows ---
  useEffect(() => {
      if (!fundMeta?.fundPk || !paginatedData.length) return;

      const fetchVisibleHistory = async () => {
          // Identify items that need fetching (have stockPk but no cache)
          const itemsToFetch = paginatedData.filter(item => 
              item.stockPk && !historyCache[item.stockPk] && !loadingHistoryMap[item.stockPk]
          );

          if (itemsToFetch.length === 0) return;

          // Mark as loading
          setLoadingHistoryMap(prev => {
              const next = { ...prev };
              itemsToFetch.forEach(i => { if(i.stockPk) next[i.stockPk] = true; });
              return next;
          });

          // Fetch in batches to avoid overwhelming the browser/proxy
          const BATCH_SIZE = 5;
          for (let i = 0; i < itemsToFetch.length; i += BATCH_SIZE) {
              const batch = itemsToFetch.slice(i, i + BATCH_SIZE);

              await Promise.all(batch.map(async (item) => {
                  if (!item.stockPk) return;
                  try {
                      const url = item.historyUrl ? (item.historyUrl.startsWith('http') ? item.historyUrl : `https://trendlyne.com${item.historyUrl}`) : '';
                      if (!url) return;
                      const history = await fetchFundHoldingHistory(url);
                      if (history && history.length > 0) {
                          // Extract only necessary data: last 6 months
                          const processed = history.slice(0, 6).map(h => ({
                              date: h["Holding Date"],
                              change: h["1M Change %"]
                          }));

                          setHistoryCache(prev => ({
                              ...prev,
                              [item.stockPk!]: processed
                          }));

                          // Update headers if this is the first successful fetch or has newer data
                          setMonthHeaders(prevHeaders => {
                              if (prevHeaders.length === 0 && processed.length > 0) {
                                  return processed.map(p => p.date);
                              }
                              return prevHeaders;
                          });
                      }
                  } catch (e) {
                      console.error(`Failed history fetch for ${item.stockSymbol}`, e);
                  } finally {
                      setLoadingHistoryMap(prev => {
                          const next = { ...prev };
                          if (item.stockPk) delete next[item.stockPk];
                          return next;
                      });
                  }
              }));
          }
      };

      fetchVisibleHistory();
  }, [paginatedData, fundMeta, historyCache, loadingHistoryMap]);


  const SortIcon = ({ field }: { field: SortField }) => {
    const isActive = sortField === field;
    return (
      <div className={`ml-1 flex flex-col ${isActive ? 'opacity-100' : 'opacity-20 group-hover:opacity-50'}`}>
         {isActive && sortDirection === 'asc' ? <ArrowUp size={12} /> : <ArrowUp size={12} className="opacity-0 h-0" />} 
         <ArrowDown size={12} className={isActive && sortDirection === 'asc' ? 'opacity-0 h-0' : ''} />
      </div>
    );
  };

  const getDotColor = (val: string) => {
      if (val === 'positive') return 'bg-green-500';
      if (val === 'negative') return 'bg-red-500';
      return 'bg-yellow-400';
  };

  const getDisplayUrl = (url: string) => {
      if (!url) return '';
      if (url.startsWith('http')) return url;
      return `https://trendlyne.com${url}`;
  };

  const renderLegendText = (value: string, entry: any) => {
    return (
        <span className="text-gray-600 font-medium ml-1 text-xs">
            {value} <span className="text-gray-400 font-normal">({entry.payload.value}%)</span>
        </span>
    );
  };

  const getHistoryChangeColor = (val: string | undefined) => {
      if (!val) return 'text-gray-300';
      if (val.includes('-')) return 'text-red-500';
      return 'text-green-500';
  };

  return (
    <div className="space-y-6">
      {/* Header Area */}
      <div className="flex items-center justify-between pb-4 border-b border-gray-100">
        <div>
           <h2 className="text-2xl font-bold text-gray-900">Fund Monitor</h2>
        </div>
      </div>

      {!selectedFund ? (
        <FundSearch onSelectFund={(fund) => setSelectedFund(fund)} />
      ) : (
        <div className="animate-fade-in space-y-6">
          <button 
            onClick={() => { setSelectedFund(null); setPortfolioData(null); setFundMeta(null); setSectorData([]); setHistoryCache({}); setMonthHeaders([]); }}
            className="flex items-center gap-2 text-sm text-gray-500 hover:text-indigo-600 transition-colors"
          >
            <ArrowLeft size={16} />
            Search different fund
          </button>

          {/* Top Section: Fund Info & Pie Chart */}
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
             {/* Fund Description Card */}
             <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6 flex flex-col justify-between">
                <div>
                    <div className="flex items-start justify-between mb-4">
                      <div>
                          <h3 className="text-2xl font-bold text-gray-900 flex items-center gap-2">
                              {selectedFund.name}
                              {selectedFund.url && (
                                  <a 
                                      href={getDisplayUrl(selectedFund.url)} 
                                      target="_blank" 
                                      rel="noreferrer"
                                      className="text-gray-400 hover:text-indigo-600 transition-colors"
                                      title="View full report on Trendlyne"
                                  >
                                      <ExternalLink size={20} />
                                  </a>
                              )}
                          </h3>
                          {loading ? (
                          <div className="h-6 w-32 bg-gray-100 animate-pulse rounded mt-2"></div>
                          ) : fundMeta?.category && (
                          <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-indigo-100 text-indigo-800 mt-2">
                              {fundMeta.category}
                          </span>
                          )}
                      </div>

                      <button 
                        onClick={handleRefresh} 
                        disabled={loading}
                        className="p-2 rounded-full hover:bg-gray-100 text-gray-400 hover:text-indigo-600 transition-colors border border-gray-100 shadow-sm"
                        title="Refresh Fund Data"
                      >
                         <RefreshCw size={18} className={loading ? "animate-spin text-indigo-600" : ""} />
                      </button>
                    </div>

                    <div className="prose prose-sm text-gray-500 max-w-none">
                    {loading ? (
                        <div className="space-y-2">
                        <div className="h-4 bg-gray-100 rounded w-full animate-pulse"></div>
                        <div className="h-4 bg-gray-100 rounded w-5/6 animate-pulse"></div>
                        <div className="h-4 bg-gray-100 rounded w-4/6 animate-pulse"></div>
                        </div>
                    ) : (
                        <p>{fundMeta?.description || "No description available for this fund category."}</p>
                    )}
                    </div>
                </div>
             </div>

             {/* Sector Pie Chart */}
             <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6 flex flex-col">
                <h4 className="font-semibold text-gray-800 mb-2 flex items-center gap-2 text-sm">
                   <PieIcon size={16} className="text-indigo-500"/>
                   Sector Allocation
                </h4>
                <div className="flex-1 min-h-[220px] relative">
                   {loading ? (
                      <div className="absolute inset-0 flex items-center justify-center">
                         <Loader2 className="animate-spin text-indigo-400" />
                      </div>
                   ) : sectorData.length > 0 ? (
                      <ResponsiveContainer width="100%" height="100%">
                         <PieChart>
                            <Pie
                               data={sectorData}
                               dataKey="value"
                               nameKey="name"
                               cx="50%"
                               cy="50%"
                               innerRadius={50}
                               outerRadius={80}
                               paddingAngle={2}
                            >
                               {sectorData.map((entry, index) => (
                                  <Cell key={`cell-${index}`} fill={CHART_COLORS[index % CHART_COLORS.length]} />
                               ))}
                            </Pie>
                            <Tooltip formatter={(value: number) => `${value}%`} />
                            <Legend 
                                layout="horizontal" 
                                verticalAlign="bottom" 
                                align="center" 
                                iconSize={8} 
                                wrapperStyle={{ fontSize: '10px', paddingTop: '10px' }}
                                formatter={renderLegendText}
                            />
                         </PieChart>
                      </ResponsiveContainer>
                   ) : (
                      <div className="h-full flex items-center justify-center text-gray-400 text-sm">
                         No sector data available
                      </div>
                   )}
                </div>
             </div>
          </div>

          {/* Holdings Table Section */}
          <div className="bg-white rounded-xl shadow-sm border border-gray-200 flex flex-col">
            <div className="px-6 py-4 border-b border-gray-200 bg-gray-50 flex items-center justify-between gap-4">
              <div className="flex items-center gap-4">
                <div className="flex items-center gap-2">
                    <h3 className="text-base font-bold text-gray-900">Portfolio Holdings</h3>
                    <span className="text-sm text-gray-500 font-medium">
                        ({loading ? '...' : portfolioData ? sortedData.length : 0})
                    </span>
                </div>

                <button
                    onClick={handleToggleFundTrack}
                    className={`flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-xs font-medium transition-colors border ${
                        isFundTracked 
                        ? 'bg-green-50 text-green-700 border-green-200 hover:bg-green-100' 
                        : 'bg-white text-indigo-600 border-indigo-200 hover:bg-indigo-50'
                    }`}
                >
                    {isFundTracked ? <Check size={14} /> : <Plus size={14} />}
                    {isFundTracked ? 'Tracked' : 'Track Fund'}
                </button>
              </div>

              <div className="flex items-center gap-4">
                  {/* Tracked Stocks Filter */}
                  <label className="flex items-center gap-2 text-xs font-medium text-gray-700 cursor-pointer select-none bg-white px-2 py-1.5 rounded-md border border-gray-200 hover:border-indigo-300 transition-colors shadow-sm">
                      <input 
                          type="checkbox" 
                          checked={showTrackedOnly} 
                          onChange={(e) => setShowTrackedOnly(e.target.checked)}
                          className="w-3.5 h-3.5 text-indigo-600 rounded focus:ring-indigo-500 border-gray-300"
                      />
                      Tracked Stocks
                  </label>

                  <div className="relative w-48">
                    <div className="absolute inset-y-0 left-0 flex items-center pl-2.5 pointer-events-none">
                      <Search className="w-3.5 h-3.5 text-gray-400" />
                    </div>
                    <input 
                      type="text" 
                      className="bg-white border border-gray-200 text-gray-900 text-xs rounded-lg focus:ring-indigo-500 focus:border-indigo-500 block w-full pl-8 p-1.5 shadow-sm" 
                      placeholder="Search holdings..." 
                      value={searchTerm}
                      onChange={(e) => setSearchTerm(e.target.value)}
                    />
                  </div>
              </div>
            </div>

            <div className="overflow-x-auto min-h-[400px]">
              {loading ? (
                  <div className="flex flex-col items-center justify-center h-64 text-gray-500 gap-3">
                      <Loader2 className="animate-spin text-indigo-600" size={32} />
                      <p>Loading real-time portfolio data...</p>
                  </div>
              ) : portfolioData && portfolioData.length > 0 ? (
                  <table className="w-full text-sm text-left text-gray-500">
                    <thead className="text-xs text-gray-700 uppercase bg-gray-50 border-b border-gray-200">
                      <tr>
                        <th 
                           scope="col" 
                           className="px-4 py-3 sticky left-0 bg-gray-50 z-10 border-r border-gray-200 w-[20%] min-w-[240px] cursor-pointer hover:bg-gray-100 group"
                           onClick={() => handleSort('stockName')}
                        >
                            <div className="flex items-center justify-between">
                                Invested In <SortIcon field="stockName"/>
                            </div>
                        </th>
                        <th 
                           scope="col" 
                           className="px-4 py-3 text-right w-[15%] cursor-pointer hover:bg-gray-100 group"
                           onClick={() => handleSort('sector')}
                        >
                             <div className="flex items-center justify-end">Sector <SortIcon field="sector"/></div>
                        </th>
                        <th 
                            scope="col" 
                            className="px-4 py-3 text-right cursor-pointer hover:bg-gray-100 group w-[10%]"
                            onClick={() => handleSort('percentage')}
                        >
                            <div className="flex items-center justify-end">% Assets <SortIcon field="percentage"/></div>
                        </th>
                        <th 
                            scope="col" 
                            className="px-4 py-3 text-right cursor-pointer hover:bg-gray-100 group w-[10%]"
                            onClick={() => handleSort('quantity')}
                        >
                            <div className="flex items-center justify-end">Quantity <SortIcon field="quantity"/></div>
                        </th>

                        {/* Dynamic History Columns - Up to 6 */}
                        {monthHeaders.length > 0 ? (
                            monthHeaders.slice(0, 6).map((header, i) => (
                                <th key={i} 
                                    scope="col" 
                                    className={`px-4 py-3 text-right w-[10%] min-w-[100px] text-gray-400 font-medium cursor-pointer hover:bg-gray-100 group`}
                                    onClick={() => handleSort(i === 0 ? 'changePercentage' : `history_${i}`)}
                                >
                                    <div className="flex items-center justify-end gap-1">
                                         <div>
                                            {header.split(' ')[0]} <br/> 
                                            <span className="text-[10px] opacity-75">{header.split(' ').slice(1).join(' ')}</span>
                                         </div>
                                         <SortIcon field={i === 0 ? 'changePercentage' : `history_${i}`}/>
                                    </div>
                                </th>
                            ))
                        ) : (
                            // Placeholder columns while loading first batch
                            [...Array(6)].map((_, i) => (
                                <th key={i} scope="col" className="px-4 py-3 text-right w-[10%] min-w-[100px] text-gray-300">
                                    M-{i}
                                </th>
                            ))
                        )}
                      </tr>
                    </thead>
                    <tbody className="divide-y divide-gray-100">
                      {paginatedData.length > 0 ? paginatedData.map((row, idx) => {
                          // Get cached history
                          const history = row.stockPk ? historyCache[row.stockPk] : undefined;
                          const isLoadingHistory = row.stockPk ? loadingHistoryMap[row.stockPk] : false;
                          const isTracked = trackedSet.has(row.stockSymbol);

                          return (
                          <tr key={idx} className="bg-white hover:bg-gray-50 transition-colors group">
                            <td className="px-4 py-3 font-medium text-gray-900 sticky left-0 bg-white group-hover:bg-gray-50 border-r border-gray-200 z-10 align-top">
                              <div className="flex items-start gap-3">
                                  {/* Tracking Checkbox */}
                                  <button 
                                      onClick={(e) => handleTrackToggle(e, row.stockSymbol, row.stockName)}
                                      className={`mt-0.5 transition-colors ${isTracked ? 'text-indigo-600' : 'text-gray-300 hover:text-gray-500'}`}
