const StockSearch: React.FC<StockSearchProps> = ({ onSelectStock }) => {
  const [query, setQuery] = useState('');
  const [suggestions, setSuggestions] = useState<Array<{ symbol: string; name: string }>>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [showDropdown, setShowDropdown] = useState(false);
  // Helper state to force re-render when tracking/ignoring changes
  const [tick, setTick] = useState(0);

  // Debounce search input
  useEffect(() => {
    const timeoutId = setTimeout(async () => {
      if (query.trim().length >= 2) {
        setIsLoading(true);
        setShowDropdown(true);
        try {
          const results = await searchStocksFromMasterList(query);
          setSuggestions(results);
        } catch (error) {
          console.error("Search failed", error);
          setSuggestions([]);
        } finally {
          setIsLoading(false);
        }
      } else {
        setShowDropdown(false);
        setSuggestions([]);
      }
    }, 300);

    return () => clearTimeout(timeoutId);
  }, [query]);

  const handleTrack = (e: React.MouseEvent, symbol: string, name: string) => {
    e.stopPropagation();
    const success = addTrackedItem({ id: symbol, name, symbol, type: 'STOCK' });
    if (!success) {
        alert(`Tracking limit reached (Max ${MAX_TRACKED_STOCKS} stocks). Please remove some items to add new ones.`);
        return;
    }
    // If tracking, ensure it's not on the ignore list
    if (isIgnored(symbol)) {
        removeIgnoredItem(symbol);
    }
    setTick(tick + 1); 
  };

  const handleIgnore = (e: React.MouseEvent, symbol: string) => {
    e.stopPropagation();
    if (isIgnored(symbol)) {
        removeIgnoredItem(symbol);
    } else {
        addIgnoredItem(symbol);
        // If ignoring, remove from tracking if it was there
        if (isTracked(symbol, 'STOCK')) {
            removeTrackedItem(symbol, 'STOCK');
        }
    }
    setTick(tick + 1);
  };

  const IgnoreButton = ({ symbol }: { symbol: string }) => {
    const ignored = isIgnored(symbol);
    return (
      <button
        onClick={(e) => handleIgnore(e, symbol)}
        className={`p-2 rounded-lg transition-all ${
           ignored 
           ? 'bg-red-50 text-red-600 shadow-sm border border-red-100' 
           : 'bg-gray-100 text-gray-400 hover:bg-red-600 hover:text-white'
        }`}
        title={ignored ? "Remove from Ignore List" : "Ignore Stock (Hide from Intelligent Tracking)"}
      >
        <EyeOff size={16} />
      </button>
    );
  };

  const TrackButton = ({ symbol, name }: { symbol: string, name: string }) => {
    const tracked = isTracked(symbol, 'STOCK');
    return (
      <button
        onClick={(e) => handleTrack(e, symbol, name)}
        className={`p-2 rounded-lg transition-all ${
           tracked 
           ? 'bg-green-50 text-green-600 cursor-default border border-green-100' 
           : 'bg-gray-100 text-gray-400 hover:bg-indigo-600 hover:text-white'
        }`}
        title={tracked ? "Added to Watchlist" : "Add to Watchlist"}
        disabled={tracked}
      >
        {tracked ? <Check size={16} /> : <Plus size={16} />}
      </button>
    );
  };

  return (
    <div className="max-w-4xl mx-auto space-y-8 animate-fade-in relative">
       <div className="text-center space-y-4 py-8">
          <h1 className="text-3xl font-bold text-gray-900">Search Indian Markets</h1>
          <p className="text-gray-500 max-w-lg mx-auto">
            Analyze any stock to see live prices powered by Gemini and check which mutual funds are holding it in their portfolios.
          </p>
       </div>

       {/* Search Input Container */}
       <div className="relative max-w-2xl mx-auto z-20">
          <div className="absolute inset-y-0 left-0 flex items-center pl-4 pointer-events-none">
            <Search className="w-5 h-5 text-gray-400" />
          </div>
          <input 
            type="text" 
            className="block w-full p-4 pl-12 text-sm text-gray-900 border border-gray-200 rounded-2xl bg-white shadow-sm focus:ring-indigo-500 focus:border-indigo-500 focus:outline-none focus:ring-2 transition-shadow" 
            placeholder="Search by Symbol (e.g., RELIANCE) or Company Name..." 
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            onFocus={() => {
              if (suggestions.length > 0 || query.length >= 2) setShowDropdown(true);
            }}
            autoFocus
          />

          {/* Search Dropdown */}
          {showDropdown && (
            <div className="absolute top-full left-0 right-0 mt-2 bg-white rounded-xl shadow-xl border border-gray-100 overflow-hidden animate-fade-in max-h-80 overflow-y-auto">
              {isLoading ? (
                <div className="p-4 flex items-center justify-center text-gray-500 gap-2 text-sm">
                  <Loader2 className="animate-spin text-indigo-600" size={18} />
                  Searching...
                </div>
              ) : suggestions.length > 0 ? (
                <div className="divide-y divide-gray-50">
                  {suggestions.map((stock, idx) => (
                    <div
                      key={`${stock.symbol}-${idx}`}
                      onClick={() => onSelectStock(stock.symbol, stock.name)}
                      className="w-full flex items-center justify-between p-3 hover:bg-indigo-50 transition-colors text-left group cursor-pointer"
                    >
                      <div className="flex items-center gap-3">
                         <div className="w-8 h-8 rounded-lg bg-indigo-100 flex items-center justify-center text-indigo-600 font-bold text-xs">
                            {stock.symbol.substring(0, 1)}
                         </div>
                         <div>
                            <div className="font-medium text-gray-900 text-sm">{stock.name}</div>
                            <div className="text-xs text-gray-500 font-mono">{stock.symbol}</div>
                         </div>
                      </div>

                      <div className="flex items-center gap-2">
                        <IgnoreButton symbol={stock.symbol} />
                        <TrackButton symbol={stock.symbol} name={stock.name} />
                        <div className="p-2 text-indigo-400 opacity-0 group-hover:opacity-100 transition-opacity">
                            <ArrowRight size={16} />
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              ) : (
                <div className="p-4 text-center text-gray-400 text-sm">
                  No matches found for "{query}"
                </div>
              )}
            </div>
          )}
       </div>

       {/* Popular Stocks Grid (Static) */}
       <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden z-10">
          <div className="p-4 border-b border-gray-100 bg-gray-50 flex items-center justify-between">
            <h3 className="font-semibold text-gray-700 flex items-center gap-2">
               <TrendingUp size={16} className="text-indigo-500"/>
               Popular Stocks
            </h3>
            <span className="text-xs text-gray-500">Most tracked</span>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 divide-y md:divide-y-0 gap-px bg-gray-100">
            {POPULAR_STOCKS.map((stock) => (
              <div 
                key={stock.symbol}
                onClick={() => onSelectStock(stock.symbol, stock.name)}
                className="bg-white p-4 hover:bg-gray-50 transition-colors text-left flex items-center justify-between group cursor-pointer"
              >
                <div className="flex items-center gap-3">
                   <div className="w-8 h-8 rounded-full bg-gray-100 flex items-center justify-center text-gray-500 font-bold text-xs group-hover:bg-indigo-100 group-hover:text-indigo-600 transition-colors">
                      {stock.symbol.substring(0, 1)}
                   </div>
                   <div>
                      <div className="font-medium text-gray-900 text-sm">{stock.name}</div>
                      <div className="text-xs text-gray-500 font-mono">{stock.symbol}</div>
                   </div>
                </div>
                <div className="flex items-center gap-2">
                    <IgnoreButton symbol={stock.symbol} />
                    <TrackButton symbol={stock.symbol} name={stock.name} />
                </div>
              </div>
            ))}
          </div>
       </div>
    </div>
  );
};

