            </svg>
            <span><strong>Limit Reached</strong>: You can track max ${MAX_TRACKED_STOCKS} stocks.</span>
        </div>
    `;
    div.style.cssText = `
        position: fixed;
        top: 24px;
        left: 50%;
        transform: translateX(-50%) translateY(-20px);
        background-color: #FEF2F2;
        color: #991B1B;
